  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 7, 'אני יוצר מופעים שמעשירים את חיי התרבות של הקהל.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 8, 'אני מחזק את הקשר בין המטפל לבין המטופל באמצעות ליצנות רפואית.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 9, 'אני מלווה תהליכי חינוך והנחיה באמצעות משחק ובידור.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 10, 'אני יוצר סיטואציות קומיות שמגבירות את האנרגיה והחיוביות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 11, 'אני מלווה ילדים חולים בתהליכי שמחה והפגת כאב.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 12, 'אני מחזק את היכולת לראות את העולם דרך פרספקטיבה קלילה וחיובית.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 13, 'אני יוצר מופעים שמעצימים ביטחון עצמי ויצירתיות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 14, 'אני מלווה תהליכים להעצמת רוח הקהל וההנאה מהחיים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 15, 'אני מעורר השראה למשתתפים דרך הומור אמיתי ומדויק.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 16, 'אני מלווה תהליכים של חיבור בין אנשים באמצעות צחוק משותף.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 17, 'אני מחזק את היכולת להביע רגשות בצורה חווייתית ומשוחררת.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 18, 'אני יוצר מופעים שמחברים בין קהל לבין תוכן חינוכי או טיפולי.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 19, 'אני מלווה תהליכים של שיפור מצב רוח באמצעות חוויה קומית.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 20, 'אני מעורר את היצירתיות והדמיון בקרב משתתפים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 21, 'אני מלווה מופעים המותאמים לצרכים רגשיים וחינוכיים שונים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 22, 'אני מחזק את היכולת לפתח כישורי ביטוי והופעה מול קהל.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 23, 'אני יוצר סדנאות ושיעורים בהם משולבים הומור ולמידה.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 24, 'אני מלווה תהליכים של הפגת מתחים בקרב צוותים ואנשים בוגרים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 25, 'אני מעורר שמחה והקלה בסיטואציות מאתגרות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 26, 'אני מלווה ילדים ובני נוער בהתמודדות עם פחדים באמצעות משחק.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 27, 'אני מחזק את היכולת ליצור קשר אנושי חיובי עם משתתפים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 28, 'אני יוצר חוויות קומיות שמפתחות דמיון ואמפתיה.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 29, 'אני מלווה מופעים שמסייעים בהטמעת מסרים חינוכיים בצורה קלילה.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 30, 'אני מעורר השראה דרך שילוב אמנות ובידור בחיי היומיום.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 31, 'אני מלווה תהליכי העצמה אישית דרך מופעים חווייתיים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 32, 'אני מחזק את היכולת להוביל קהל ולהעביר חוויות משמעותיות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 33, 'אני יוצר מופעים שמאפשרים חיבור רגשי בין משתתפים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 34, 'אני מלווה תהליכים שמפתחים כישורים חברתיים ותקשורתיים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 35, 'אני מעורר מצב רוח חיובי באמצעות הומור ואמנות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 36, 'אני מלווה ילדים חולים ומשפחותיהם בהפגת פחד וכאב.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 37, 'אני מחזק את היכולת להסתכל על החיים בפרספקטיבה חיובית.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 38, 'אני יוצר מופעים שמפיחים השראה ותחושת שייכות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 39, 'אני מלווה תהליכים שמעצימים כישורי ביטוי והופעה.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 40, 'אני מעורר שמחה וצחוק בקרב אוכלוסיות מגוונות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 41, 'אני מלווה תהליכים טיפוליים דרך ליצנות רפואית והומור.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 42, 'אני מחזק את היכולת ליזום ולהוביל פעילויות בידור וחינוך.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 43, 'אני יוצר מופעים שמחברים בין אמנות לצרכים טיפוליים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 44, 'אני מלווה תהליכים שמאפשרים ביטוי עצמי חופשי ומשוחרר.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 45, 'אני מעורר השראה והנאה בקרב משתתפים בכל גיל.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 46, 'אני מלווה מופעים שמחזקים את הביטחון העצמי והיכולת להביע רגשות.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 47, 'אני מחזק את הקשר בין מטפל למטופל באמצעות הומור.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 48, 'אני יוצר סדנאות המשלבות חינוך, אומנות ובידור.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 49, 'אני מלווה תהליכים שמפתחים כישורים חברתיים ורגשיים.'),
  (45, 'בידור וליצנות רפואית', 'קומיקאים, מנחי טלוויזיה, ליצנים רפואיים', 50, 'אני מסייע להפוך רגעים קשים לרגעים של שמחה והקלה.')
